patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..65bd10a88617 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -442,19 +442,34 @@ Instruction *InstCombinerImpl::foldSelectOpOp(SelectInst &SI, Instruction *TI,
   }

   // Only handle binary operators (including two-operand getelementptr) with
-  // one-use here. As with the cast case above, it may be possible to relax the
-  // one-use constraint, but that needs be examined carefully since it may not
-  // reduce the total number of instructions.
+  if (auto *TSel = dyn_cast<SelectInst>(TI)) {
+    if (auto *FSel = dyn_cast<SelectInst>(FI)) {
+      if (TI->hasOneUse() && FI->hasOneUse()) {
+        // Handle select(C2, select(C1, A, B), select(C1, B, A)) -> select(C1^C2, B, A)
+        Value *C1 = TSel->getCondition();
+        if (C1 == FSel->getCondition() && TSel->getTrueValue() == FSel->getFalseValue() &&
+            TSel->getFalseValue() == FSel->getTrueValue()) {
+          if (C1->getType() == CondTy) {
+            Value *Xor = Builder.CreateXor(C1, Cond);
+            return SelectInst::Create(Xor, TSel->getFalseValue(), TSel->getTrueValue());
+          }
+        }
+      }
+    }
+  }
+
   if (TI->getNumOperands() != 2 || FI->getNumOperands() != 2 ||
       !TI->isSameOperationAs(FI) ||
-      (!isa<BinaryOperator>(TI) && !isa<GetElementPtrInst>(TI)) ||
+      (!isa<BinaryOperator>(TI) && !isa<GetElementPtrInst>(TI) &&
+       !isa<SelectInst>(TI)) ||
       !TI->hasOneUse() || !FI->hasOneUse())
     return nullptr;

   // Figure out if the operations have any operands in common.
   Value *MatchOp = getCommonOp(TI, FI, TI->isCommutative());
-  if (!MatchOp)
+  if (!MatchOp) {
     return nullptr;
+  }

   // If the select condition is a vector, the operands of the original select's
   // operands also must be vectors. This may not be the case for getelementptr
@@ -495,10 +510,12 @@ Instruction *InstCombinerImpl::foldSelectOpOp(SelectInst &SI, Instruction *TI,
     return GetElementPtrInst::Create(
         ElementType, Op0, Op1, TGEP->getNoWrapFlags() & FGEP->getNoWrapFlags());
   }
-  llvm_unreachable("Expected BinaryOperator or GEP");
+  if (auto *Sel = dyn_cast<SelectInst>(TI)) {
+    return SelectInst::Create(Sel->getCondition(), Op0, Op1);
+  }
+  llvm_unreachable("Expected BinaryOperator, GEP, or SelectInst");
   return nullptr;
 }
-
 static bool isSelect01(const APInt &C1I, const APInt &C2I) {
   if (!C1I.isZero() && !C2I.isZero()) // One side must be zero.
     return false;

