{"command":"cd /app/data/auto-opt/utils/llvm-98800 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp 444 471
  // Only handle binary operators (including two-operand getelementptr) with
  // one-use here. As with the cast case above, it may be possible to relax the
  // one-use constraint, but that needs be examined carefully since it may not
  // reduce the total number of instructions.

  if (auto *TSel = dyn_cast<SelectInst>(TI)) {
    if (auto *FSel = dyn_cast<SelectInst>(FI)) {
      // Handle select(C2, select(C1, A, B), select(C1, B, A)) -> select(C1^C2, B, A)
      Value *C1 = TSel->getCondition();
      if (C1 == FSel->getCondition() && TSel->getTrueValue() == FSel->getFalseValue() &&
          TSel->getFalseValue() == FSel->getTrueValue()) {
        Value *Xor = Builder.CreateXor(C1, Cond);
        return SelectInst::Create(Xor, TSel->getFalseValue(), TSel->getTrueValue());
      }
    }
  }

  if (TI->getNumOperands() != 2 || FI->getNumOperands() != 2 ||
      !TI->isSameOperationAs(FI) ||
      (!isa<BinaryOperator>(TI) && !isa<GetElementPtrInst>(TI) &&
       !isa<SelectInst>(TI)) ||
      !TI->hasOneUse() || !FI->hasOneUse())
    return nullptr;

  // Figure out if the operations have any operands in common.
  Value *MatchOp = getCommonOp(TI, FI, TI->isCommutative());
  if (!MatchOp) {
    return nullptr;
  }
CODEEOF"}

